// ====================================================================
// ðŸ”§ PARSE LEARNING REQUEST + 4-LEVEL INSTRUCTION ROUTER
// Extracts form data and sets level-specific writing instructions.
// This is the core differentiation engine â€” it controls the depth,
// tone, and complexity of the entire output document.
// ====================================================================

const formData = $input.first().json;

const topic = formData['Topic I Want to Learn'] || formData['field-0'] || 'AI Automation';
const level = formData['My Knowledge Level'] || formData['field-1'] || 'Complete Beginner';
const specificQuestions = formData['What I Want to Understand'] || formData['field-2'] || '';
const email = formData['Notification Email'] || formData['field-3'] || '';

let levelInstruction = '';
switch(level) {
  case 'Complete Beginner':
    levelInstruction = 'Write for someone who has never encountered this topic. Use everyday analogies and real-world comparisons. Define every technical term the first time it appears. Assume zero prior knowledge. Focus on building a strong mental model from scratch. Use scenarios like imagine you are... to make abstract concepts concrete.';
    break;
  case 'Intermediate Practitioner':
    levelInstruction = 'Write for someone who understands the basics and has some hands-on experience. Skip introductory definitions. Focus on practical applications, common pitfalls, and real-world case studies. Include comparison tables, decision frameworks, and specific metrics where available.';
    break;
  case 'Advanced Professional':
    levelInstruction = 'Write for an experienced professional who works with this topic regularly. Focus on edge cases, advanced patterns, optimization techniques, and research-backed insights. Include specific metrics, benchmarks, industry data, and contrarian perspectives where supported by evidence.';
    break;
  case 'Expert / Deep Dive':
    levelInstruction = 'Write at the deepest possible technical and strategic depth. Reference academic research, recent papers, and developments from 2024-2026. Challenge conventional wisdom where evidence supports it. Include detailed technical analysis, trade-off matrices, architectural decisions, and forward-looking projections.';
    break;
  default:
    levelInstruction = 'Write a comprehensive overview suitable for a general audience with practical takeaways.';
}

const timestamp = new Date().toISOString();
const dateStr = new Date().toLocaleDateString('en-IN', { year:'numeric', month:'long', day:'numeric' });

// Detect topic category for document organization
const topicLower = topic.toLowerCase();
let category = 'General';
if (/marketing|brand|seo|content|social|advertis|copywriting/.test(topicLower)) category = 'Marketing';
else if (/business|startup|entrepreneur|revenue|pricing|strategy|management/.test(topicLower)) category = 'Business';
else if (/ai |artificial|machine learning|deep learning|neural|llm|gpt|agent/.test(topicLower)) category = 'AI & Technology';
else if (/health|wellness|nutrition|supplement|skincare|beauty|ingredient/.test(topicLower)) category = 'Health & Wellness';
else if (/finance|invest|accounting|tax|budget|crypto/.test(topicLower)) category = 'Finance';
else if (/code|programming|software|developer|api|database/.test(topicLower)) category = 'Engineering';
else if (/design|ux|ui|figma|brand identity/.test(topicLower)) category = 'Design';

return [{ json: {
  topic,
  level,
  specificQuestions,
  email,
  levelInstruction,
  timestamp,
  dateStr,
  category,
  isAdvanced: level === 'Advanced Professional' || level === 'Expert / Deep Dive'
}}];

// ====================================================================
// ðŸ”€ PARSE RESEARCH PLAN
// Parses the AI planner output into structured sub-questions and
// search queries. Includes robust fallback if GPT returns invalid JSON.
// ====================================================================

const aiResp = $input.first().json;
const formData = $('ðŸ”§ Parse Learning Request').first().json;

let plan = {};
try {
  const raw = aiResp?.message?.content || '{}';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  plan = JSON.parse(cleaned);
} catch (e) {
  // Fallback: generate sensible defaults from the topic
  plan = {
    sub_questions: [
      `What is ${formData.topic} and why does it matter?`,
      `How does ${formData.topic} work in practice?`,
      `What are the key components or concepts within ${formData.topic}?`,
      `What tools and platforms are used for ${formData.topic}?`,
      `What are common mistakes people make with ${formData.topic}?`,
      `What are the latest trends in ${formData.topic} for 2026?`
    ],
    youtube_queries: [
      `${formData.topic} explained for beginners`,
      `${formData.topic} tutorial 2025 2026`,
      `${formData.topic} how it works`,
      `what is ${formData.topic}`,
      `${formData.topic} practical examples`
    ],
    web_queries: [
      `${formData.topic} complete guide 2026`,
      `${formData.topic} best practices`,
      `${formData.topic} explained simply`
    ]
  };
}

const subQuestions = plan.sub_questions || [];
const youtubeQueries = plan.youtube_queries || [];
const webQueries = plan.web_queries || [];

return [{ json: {
  ...formData,
  subQuestions,
  youtubeQueries,
  webQueries,
  subQuestionCount: subQuestions.length,
  researchPlanReady: true
}}];

