// ðŸ“Š EXTRACT VIDEO DETAILS
// Parses YouTube API response into clean video metadata.
// Prepares top 3 video URLs for Apify transcript extraction.
// ====================================================================

const resp = $input.first().json;
const formData = $('ðŸ”€ Parse Research Plan').first().json;
const items = resp.items || [];

const videos = items.map((item, idx) => {
  const snippet = item.snippet || {};
  const videoId = item.id?.videoId || '';
  return {
    index: idx + 1,
    title: snippet.title || 'Untitled',
    channel: snippet.channelTitle || 'Unknown',
    description: (snippet.description || '').slice(0, 300),
    url: `https://www.youtube.com/watch?v=${videoId}`,
    videoId: videoId,
    publishedAt: snippet.publishedAt || '',
    thumbnail: snippet.thumbnails?.high?.url || ''
  };
}).filter(v => v.url.includes('watch?v='));

// Top 3 video URLs for transcript extraction
const topVideoUrls = videos.slice(0, 3).map(v => v.url);

return [{ json: {
  ...formData,
  youtubeVideos: videos,
  youtubeCount: videos.length,
  topVideoUrls
}}];

// ====================================================================
// ðŸ§© BUILD RAG CONTEXT
// Merges ALL research data: YouTube metadata, Apify transcripts,
// SerpAPI web results, and sub-questions into a single structured
// context block that feeds the AI writer. This is where v2's research
// depth advantage is assembled.
// ====================================================================

const formData = $('ðŸ”§ Parse Learning Request').first().json;
const researchPlan = $('ðŸ”€ Parse Research Plan').first().json;
const videoData = $('ðŸ“Š Extract Video Details').first().json;

// Parse Apify transcripts (may have failed - handle gracefully)
let transcripts = [];
let transcriptText = '';
try {
  const apifyRaw = $('ðŸŽ¬ Apify: Fetch Transcripts').first().json;
  if (apifyRaw && !apifyRaw.error && !apifyRaw.errorMessage) {
    // Apify returns array of items or single object
    const items = Array.isArray(apifyRaw) ? apifyRaw : [apifyRaw];
    transcripts = items.filter(i => i.transcript || i.text).map(i => ({
      title: i.title || i.videoTitle || 'Video',
      transcript: (i.transcript || i.text || '').slice(0, 3000),
      url: i.url || i.videoUrl || ''
    }));
    transcriptText = transcripts.map(t =>
      `[TRANSCRIPT: ${t.title}]\n${t.transcript}\n[END TRANSCRIPT]`
    ).join('\n\n');
  }
} catch(e) {
  transcripts = [];
  transcriptText = '(No transcripts available - Apify extraction was skipped)';
}

// Parse SerpAPI web results (may have failed - handle gracefully)
let webResults = [];
let webText = '';
try {
  const serpRaw = $('ðŸ” SerpAPI: Web Search').first().json;
  if (serpRaw && serpRaw.organic_results) {
    webResults = serpRaw.organic_results.slice(0, 5).map(r => ({
      title: r.title || '',
      snippet: r.snippet || '',
      url: r.link || '',
      source: r.source || ''
    }));
    webText = webResults.map(r =>
      `[WEB SOURCE: ${r.title}]\nSnippet: ${r.snippet}\nURL: ${r.url}\n[END SOURCE]`
    ).join('\n\n');
  }
} catch(e) {
  webResults = [];
  webText = '(No web results available - SerpAPI was skipped)';
}

// Build all-sources list for citations
const allSources = [];
videoData.youtubeVideos.forEach(v => {
  allSources.push({ title: v.title, url: v.url, type: 'YouTube Video' });
});
transcripts.forEach(t => {
  if (t.url) allSources.push({ title: t.title, url: t.url, type: 'YouTube Transcript' });
});
webResults.forEach(r => {
  allSources.push({ title: r.title, url: r.url, type: 'Web Article' });
});

// Build the comprehensive RAG context
const subQuestionsBlock = researchPlan.subQuestions.map((q, i) =>
  `${i+1}. ${q}`
).join('\n');

const youtubeBlock = videoData.youtubeVideos.map((v, i) =>
  `${i+1}. ${v.title} by ${v.channel} (${v.url})\n   ${v.description}`
).join('\n');

const ragContext = `=== SUB-QUESTIONS TO ADDRESS ===\n${subQuestionsBlock}\n\n=== YOUTUBE VIDEOS FOUND (${videoData.youtubeCount}) ===\n${youtubeBlock}\n\n=== YOUTUBE TRANSCRIPTS (ACTUAL CONTENT) ===\n${transcriptText}\n\n=== WEB RESEARCH RESULTS ===\n${webText}`;

